// Total count helpers
export function totalDashboardCount() {
  return OBSERVABILITY_PHASES.reduce((sum, p) => sum + p.totalDashboards, 0);
}

export function dashboardsForPhase(phaseId) {
  const phase = OBSERVABILITY_PHASES.find((p) => p.id === phaseId);
  if (!phase) return [];
  return phase.categories.flatMap((c) =>
    c.dashboards.map((d) => ({ ...d, category: c.label, phase: phase.label, phaseColor: phase.color }))
  );
}

